import{_ as t,o,c as a,ae as s}from"./chunks/framework.CiBL6oPQ.js";const p=JSON.parse('{"title":"Development Rules & Conventions","description":"","frontmatter":{},"headers":[],"relativePath":"internal/ruleDevelop.md","filePath":"internal/ruleDevelop.md"}'),r={name:"internal/ruleDevelop.md"};function l(i,e,n,c,d,u){return o(),a("div",null,[...e[0]||(e[0]=[s('<h1 id="development-rules-conventions" tabindex="-1">Development Rules &amp; Conventions <a class="header-anchor" href="#development-rules-conventions" aria-label="Permalink to &quot;Development Rules &amp; Conventions&quot;">​</a></h1><h2 id="general-standards" tabindex="-1">General Standards <a class="header-anchor" href="#general-standards" aria-label="Permalink to &quot;General Standards&quot;">​</a></h2><h2 id="code-style-like-senior-developer" tabindex="-1">Code style like senior developer <a class="header-anchor" href="#code-style-like-senior-developer" aria-label="Permalink to &quot;Code style like senior developer&quot;">​</a></h2><h3 id="file-naming" tabindex="-1">File Naming <a class="header-anchor" href="#file-naming" aria-label="Permalink to &quot;File Naming&quot;">​</a></h3><ul><li><strong>Controllers</strong>: Use camelCase (e.g., <code>kafkaController.ts</code>, <code>userController.ts</code>).</li><li><strong>Services</strong>: Use camelCase (e.g., <code>kafkaService.ts</code>, <code>userService.ts</code>) or PascalCase depending on export type. Class-based services should generally match class name.</li><li><strong>Routes</strong>: Use camelCase (e.g., <code>userRoutes.ts</code>, <code>kafkaRoutes.ts</code>).</li><li><strong>Utilities</strong>: Use camelCase (e.g., <code>httpCodes.ts</code>).</li></ul><h3 id="code-style" tabindex="-1">Code Style <a class="header-anchor" href="#code-style" aria-label="Permalink to &quot;Code Style&quot;">​</a></h3><ul><li><strong>Status Codes</strong>: ALWAYS use <code>HTTP_STATUS</code> constants from <code>@/utils/httpCodes</code> (TS) or <code>../../utils/httpCodes.js</code> (JS) instead of hardcoded numbers. <ul><li>Good: <code>res.status(HTTP_STATUS.OK).json(...)</code></li><li>Bad: <code>res.status(200).json(...)</code></li></ul></li><li><strong>Imports</strong>: <ul><li><strong>TypeScript</strong>: Use path aliases (e.g., <code>@/services/...</code>, <code>@/utils/...</code>) instead of relative paths (e.g., <code>../../utils/...</code>).</li><li><strong>JavaScript</strong>: Use relative paths as configured by the project structure.</li></ul></li></ul><h3 id="api-response-structure" tabindex="-1">API Response Structure <a class="header-anchor" href="#api-response-structure" aria-label="Permalink to &quot;API Response Structure&quot;">​</a></h3><ul><li>Success: <code>{ status: string, data: any }</code> or direct JSON object.</li><li>Error: <code>{ error: string }</code></li></ul><h3 id="apply-unit-test" tabindex="-1">Apply unit test <a class="header-anchor" href="#apply-unit-test" aria-label="Permalink to &quot;Apply unit test&quot;">​</a></h3><ul><li>Apply unit test for each layer</li><li>Apply unit test for each usecase</li></ul><h2 id="git-workflow" tabindex="-1">Git Workflow <a class="header-anchor" href="#git-workflow" aria-label="Permalink to &quot;Git Workflow&quot;">​</a></h2><ul><li>Commit messages should be descriptive.</li><li>Ensure all tests pass before pushing.</li></ul><h2 id="verify-function-before-commit" tabindex="-1">Verify function before commit <a class="header-anchor" href="#verify-function-before-commit" aria-label="Permalink to &quot;Verify function before commit&quot;">​</a></h2><ul><li>npm run test:e2e</li></ul><h2 id="verify-case-sensitivity-before-commit" tabindex="-1">Verify case sensitivity before commit <a class="header-anchor" href="#verify-case-sensitivity-before-commit" aria-label="Permalink to &quot;Verify case sensitivity before commit&quot;">​</a></h2>',16)])])}const m=t(r,[["render",l]]);export{p as __pageData,m as default};
